from flask import Flask, request, jsonify
import cv2
import face_recognition
import numpy as np
import os
from sklearn import svm
from sklearn.preprocessing import LabelEncoder
from sklearn.pipeline import make_pipeline
from sklearn.preprocessing import StandardScaler

app = Flask(__name__)

# Load training images and train the SVM model
def train_model(training_images_path):
    encodings = []
    names = []

    for employee in os.listdir(training_images_path):
        if not os.path.isdir(os.path.join(training_images_path, employee)):
            continue
        
        for img_name in os.listdir(os.path.join(training_images_path, employee)):
            image_path = os.path.join(training_images_path, employee, img_name)
            image = face_recognition.load_image_file(image_path)
            face_encodings = face_recognition.face_encodings(image)
            
            if len(face_encodings) > 0:
                encodings.append(face_encodings[0])
                names.append(employee)
    
    label_encoder = LabelEncoder()
    labels = label_encoder.fit_transform(names)

    clf = make_pipeline(StandardScaler(), svm.SVC(probability=True))
    clf.fit(encodings, labels)
    
    return clf, label_encoder

model, label_encoder = train_model('employee_photos')

@app.route('/recognize', methods=['POST'])
def recognize():
    if 'image' not in request.files:
        return jsonify({'error': 'No image part'}), 400
    
    file = request.files['image']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    image = face_recognition.load_image_file(file)
    face_encodings = face_recognition.face_encodings(image)

    if len(face_encodings) == 0:
        return jsonify({'error': 'No face detected'}), 400

    face_encoding = face_encodings[0]
    probabilities = model.predict_proba([face_encoding])[0]

    results = {label_encoder.inverse_transform([i])[0]: float(prob) for i, prob in enumerate(probabilities)}
    return jsonify(results)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)